  1→export interface TOCItem {
  2→  level: number
  3→  text: string
  4→  slug: string
  5→}
  6→
  7→export interface TableOfContentsProps {
  8→  items: TOCItem[]
  9→  onNavigate?: () => void
 10→  activeSlug?: string
 11→}
 12→
 13→export function TableOfContents({ items, onNavigate, activeSlug }: TableOfContentsProps) {
 14→  const handleClick = (slug: string) => {
 15→    // Scroll to heading
 16→    const element = document.getElementById(slug)
 17→    if (element) {
 18→      element.scrollIntoView({ behavior: 'smooth' })
 19→    }
 20→    onNavigate?.()
 21→  }
 22→
 23→  return (
 24→    <nav class="pressy-toc" aria-label="Table of contents">
 25→      <h2 class="pressy-toc-title">Contents</h2>
 26→      <ul class="pressy-toc-list">
 27→        {items.map((item) => (
 28→          <li
 29→            key={item.slug}
 30→            class={`pressy-toc-item pressy-toc-level-${item.level}`}
 31→            data-active={activeSlug === item.slug}
 32→          >
 33→            <a
 34→              href={`#${item.slug}`}
 35→              onClick={(e) => {
 36→                e.preventDefault()
 37→                handleClick(item.slug)
 38→              }}
 39→              class="pressy-toc-link"
 40→            >
 41→              {item.text}
 42→            </a>
 43→          </li>
 44→        ))}
 45→      </ul>
 46→
 47→      <style>{`
 48→        .pressy-toc {
 49→          font-size: var(--font-size-sm);
 50→        }
 51→
 52→        .pressy-toc-title {
 53→          font-size: var(--font-size-base);
 54→          font-weight: 600;
 55→          margin-bottom: 1rem;
 56→          color: var(--color-heading);
 57→        }
 58→
 59→        .pressy-toc-list {
 60→          list-style: none;
 61→          padding: 0;
 62→          margin: 0;
 63→        }
 64→
 65→        .pressy-toc-item {
 66→          margin-bottom: 0.5rem;
 67→        }
 68→
 69→        .pressy-toc-level-1 {
 70→          padding-left: 0;
 71→        }
 72→
 73→        .pressy-toc-level-2 {
 74→          padding-left: 1rem;
 75→        }
 76→
 77→        .pressy-toc-level-3 {
 78→          padding-left: 2rem;
 79→        }
 80→
 81→        .pressy-toc-level-4 {
 82→          padding-left: 3rem;
 83→        }
 84→
 85→        .pressy-toc-link {
 86→          color: var(--color-text-muted);
 87→          text-decoration: none;
 88→          transition: color 0.15s;
 89→          display: block;
 90→          padding: 0.25rem 0;
 91→        }
 92→
 93→        .pressy-toc-link:hover {
 94→          color: var(--color-text);
 95→        }
 96→
 97→        .pressy-toc-item[data-active="true"] .pressy-toc-link {
 98→          color: var(--color-accent);
 99→          font-weight: 500;
100→        }
101→      `}</style>
102→    </nav>
103→  )
104→}
