 97→// ── Scroll Reader ────────────────────────────────────────────
 98→
 99→export interface ScrollReaderProps {
100→  children: ComponentChildren;
101→  bookTitle?: string;
102→  prevChapter?: { slug: string; title: string };
103→  nextChapter?: { slug: string; title: string };
104→  showDropCap: boolean;
105→  onSaveProgress?: (data: ProgressData) => void;
106→  onRestoreProgress?: () => Promise<ProgressData | null>;
107→  allChapters?: Array<{ slug: string; title: string; wordCount?: number }>;
108→  bookBasePath?: string;
109→  currentChapterSlug?: string;
110→  offlineProps?: OfflineProps;
111→}
112→
113→export function ScrollReader({
114→  children,
115→  bookTitle,
116→  prevChapter,
117→  nextChapter,
118→  showDropCap,
119→  onSaveProgress,
120→  onRestoreProgress,
121→  allChapters,
122→  bookBasePath,
123→  currentChapterSlug,
124→  offlineProps,
125→}: ScrollReaderProps) {
126→  const saveTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
127→
128→  // Footer visibility
129→  const [footerVisible, setFooterVisible] = useState(false);
130→  const footerTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
131→  const [settingsOpen, setSettingsOpen] = useState(false);
132→  const [tocOpen, setTocOpen] = useState(false);
133→
134→  const showFooterTemporarily = useCallback(() => {
135→    setFooterVisible(true);
136→    if (footerTimerRef.current) clearTimeout(footerTimerRef.current);
137→    footerTimerRef.current = setTimeout(() => setFooterVisible(false), 3000);
138→  }, []);
139→
140→  // Settings state
141→  const [activeTheme, setActiveTheme] = useState<string>(() => {
142→    if (typeof localStorage !== "undefined") {
143→      return localStorage.getItem("pressy-theme") || "light";
144→    }
145→    return "light";
146→  });
147→  const [fontScale, setFontScale] = useState<number>(() => {
148→    if (typeof localStorage !== "undefined") {
149→      const saved = localStorage.getItem("pressy-font-size");
150→      return saved ? parseFloat(saved) : 1.0;
151→    }
152→    return 1.0;
153→  });
154→
155→  const applyFontScale = useCallback((scale: number) => {
156→    if (scale === 1.0) {
157→      document.documentElement.style.removeProperty("--font-size-base");
158→    } else {
159→      document.documentElement.style.setProperty(
160→        "--font-size-base",
161→        `calc(clamp(1rem, 0.875rem + 0.5vw, 1.25rem) * ${scale})`
162→      );
163→    }
164→  }, []);
165→
166→  useEffect(() => {
167→    if (fontScale !== 1.0) {
168→      applyFontScale(fontScale);
169→    }
170→  }, []);
171→
172→  const handleThemeChange = useCallback((theme: string) => {
173→    setActiveTheme(theme);
174→    localStorage.setItem("pressy-theme", theme);
175→    const resolved =
176→      theme === "system"
177→        ? window.matchMedia("(prefers-color-scheme: dark)").matches
178→          ? "dark"
179→          : "light"
180→        : theme;
181→    document.documentElement.setAttribute("data-theme", resolved);
182→  }, []);
183→
184→  const handleFontSizeChange = useCallback(
185→    (delta: number) => {
186→      setFontScale((prev) => {
187→        const next =
188→          Math.round(Math.max(0.8, Math.min(1.5, prev + delta)) * 10) / 10;
189→        localStorage.setItem("pressy-font-size", String(next));
190→        applyFontScale(next);
191→        return next;
192→      });
193→    },
194→    [applyFontScale]
195→  );
196→
197→  // Toggle footer on tap
198→  const handleReaderClick = useCallback(
199→    (e: MouseEvent) => {
200→      const target = e.target as HTMLElement;
201→      if (
202→        target.closest(
203→          ".pressy-page-footer, .pressy-toc-backdrop, .pressy-toc-toggle"
204→        )
205→      )
206→        return;
207→      if (target.closest('a, button, input, select, textarea, [role="button"]'))
208→        return;
209→
210→      if (settingsOpen || tocOpen) {
211→        setSettingsOpen(false);
212→        setTocOpen(false);
213→        return;
214→      }
215→
216→      if (footerVisible) {
217→        setFooterVisible(false);
218→        if (footerTimerRef.current) clearTimeout(footerTimerRef.current);
219→      } else {
220→        showFooterTemporarily();
221→      }
222→    },
223→    [footerVisible, settingsOpen, tocOpen, showFooterTemporarily]
224→  );
225→
226→  // Restore scroll position on mount
227→  useEffect(() => {
228→    if (!onRestoreProgress) return;
229→    onRestoreProgress().then((data) => {
230→      if (data && data.scrollPosition > 0) {
231→        window.scrollTo(0, data.scrollPosition);
232→      }
233→    });
234→  }, []);
235→
236→  // Save scroll position (debounced)
237→  useEffect(() => {
238→    if (!onSaveProgress) return;
239→
240→    const handleScroll = () => {
241→      if (saveTimerRef.current) clearTimeout(saveTimerRef.current);
242→      saveTimerRef.current = setTimeout(() => {
243→        onSaveProgress({
244→          page: 0,
245→          totalPages: 0,
246→          scrollPosition: window.scrollY,
247→        });
248→      }, 500);
249→    };
250→
251→    window.addEventListener("scroll", handleScroll, { passive: true });
252→    return () => {
253→      window.removeEventListener("scroll", handleScroll);
254→      if (saveTimerRef.current) clearTimeout(saveTimerRef.current);
255→    };
256→  }, [onSaveProgress]);
257→
258→  // Save on page unload
259→  useEffect(() => {
260→    if (!onSaveProgress) return;
261→
262→    const handleUnload = () => {
263→      onSaveProgress({
264→        page: 0,
265→        totalPages: 0,
266→        scrollPosition: window.scrollY,
267→      });
268→    };
269→
270→    const handleVisibilityChange = () => {
271→      if (document.visibilityState === "hidden") handleUnload();
272→    };
273→
274→    window.addEventListener("beforeunload", handleUnload);
275→    document.addEventListener("visibilitychange", handleVisibilityChange);
276→    return () => {
277→      window.removeEventListener("beforeunload", handleUnload);
278→      document.removeEventListener("visibilitychange", handleVisibilityChange);
279→    };
280→  }, [onSaveProgress]);
281→
282→  return (
283→    <div class="pressy-reader" onClick={handleReaderClick}>
284→      <main class="pressy-reader-main">
285→        <article
286→          class={`pressy-prose ${showDropCap ? "" : "no-drop-cap"}`}
287→          data-drop-cap={showDropCap}
288→        >
289→          {children}
290→        </article>
291→      </main>
292→
293→      <TextShare />
294→      <Navigation prev={prevChapter} next={nextChapter} />
295→      <OfflineIndicator />
296→
297→      {/* TOC drawer overlay */}
298→      {tocOpen && allChapters && (
299→        <div
300→          class="pressy-toc-backdrop pressy-toc-backdrop--scroll"
301→          onClick={(e: MouseEvent) => {
302→            e.stopPropagation();
303→            setTocOpen(false);
304→          }}
305→        >
306→          <div
307→            class="pressy-toc-drawer"
308→            onClick={(e: MouseEvent) => e.stopPropagation()}
309→          >
310→            <div class="pressy-toc-header">
311→              <span class="pressy-toc-title">Contents</span>
312→              <button
313→                class="pressy-toc-close"
314→                onClick={(e: MouseEvent) => {
315→                  e.stopPropagation();
316→                  setTocOpen(false);
317→                }}
318→                aria-label="Close table of contents"
319→              >
320→                <svg
321→                  viewBox="0 0 24 24"
322→                  fill="none"
323→                  stroke="currentColor"
324→                  stroke-width="2"
325→                  width="18"
326→                  height="18"
327→                >
328→                  <line x1="18" y1="6" x2="6" y2="18" />
329→                  <line x1="6" y1="6" x2="18" y2="18" />
330→                </svg>
331→              </button>
332→            </div>
333→            <nav class="pressy-toc-list">
334→              <a
335→                href={bookBasePath ? bookBasePath.replace(/\/books\/[^/]+$/, '') || '/' : '/'}
336→                class="pressy-toc-item pressy-toc-item--home"
337→                onClick={() => setTocOpen(false)}
338→              >
