345→              </a>
346→              {allChapters.map((ch, i) => (
347→                <a
348→                  key={ch.slug}
349→                  href={`${bookBasePath || ""}/${ch.slug}`}
350→                  class={`pressy-toc-item ${
351→                    ch.slug === currentChapterSlug
352→                      ? "pressy-toc-item--active"
353→                      : ""
354→                  }`}
355→                  onClick={() => setTocOpen(false)}
356→                >
357→                  <span class="pressy-toc-item-num">{i + 1}.</span>
358→                  <span class="pressy-toc-item-title">{ch.title}</span>
359→                </a>
360→              ))}
361→            </nav>
362→          </div>
363→        </div>
364→      )}
365→
366→      {/* Footer */}
367→      <div
368→        class={`pressy-page-footer pressy-page-footer--scroll ${
369→          footerVisible || settingsOpen || tocOpen
370→            ? "pressy-page-footer--visible"
371→            : ""
372→        }`}
373→      >
374→        <div class="pressy-footer-row">
375→          {allChapters && allChapters.length > 0 && (
376→            <button
377→              class="pressy-toc-toggle"
378→              onClick={(e: MouseEvent) => {
379→                e.stopPropagation();
380→                setSettingsOpen(false);
381→                setTocOpen(!tocOpen);
382→              }}
383→              aria-label="Table of contents"
384→            >
385→              <svg
386→                viewBox="0 0 24 24"
387→                fill="none"
388→                stroke="currentColor"
389→                stroke-width="1.5"
390→                stroke-linecap="round"
391→                stroke-linejoin="round"
392→                width="18"
393→                height="18"
394→              >
395→                <line x1="3" y1="6" x2="21" y2="6" />
396→                <line x1="3" y1="12" x2="21" y2="12" />
397→                <line x1="3" y1="18" x2="21" y2="18" />
398→              </svg>
399→            </button>
400→          )}
401→          {bookTitle && (
402→            <button
403→              class="pressy-footer-title"
404→              onClick={(e: MouseEvent) => {
405→                e.stopPropagation();
406→                if (allChapters && allChapters.length > 0) {
407→                  setSettingsOpen(false);
