549→              ))}
550→            </div>
551→          </div>
552→          <div class="pressy-settings-section">
553→            <div class="pressy-settings-label">Font Size</div>
554→            <div class="pressy-font-size-controls">
555→              <button
556→                class="pressy-font-size-btn"
557→                onClick={(e: MouseEvent) => {
558→                  e.stopPropagation();
559→                  handleFontSizeChange(-0.1);
560→                }}
561→                disabled={fontScale <= 0.8}
562→                aria-label="Decrease font size"
563→              >
564→                A-
565→              </button>
566→              <span class="pressy-font-size-value">
567→                {Math.round(fontScale * 100)}%
568→              </span>
569→              <button
570→                class="pressy-font-size-btn"
571→                onClick={(e: MouseEvent) => {
572→                  e.stopPropagation();
573→                  handleFontSizeChange(0.1);
574→                }}
575→                disabled={fontScale >= 1.5}
576→                aria-label="Increase font size"
577→              >
578→                A+
579→              </button>
580→            </div>
581→          </div>
582→        </div>
583→      </div>
584→
585→      <style>{SCROLL_STYLES}</style>
586→    </div>
587→  );
588→}
