 51→export function PaginatedReader({
 52→  children,
 53→  bookTitle,
 54→  prevChapter,
 55→  nextChapter,
 56→  showDropCap,
 57→  onSaveProgress,
 58→  onRestoreProgress,
 59→  bookProgressPercent,
 60→  initialContent,
 61→  chapterMapData,
 62→  currentChapterSlug,
 63→  allChapters,
 64→  bookBasePath,
 65→  onChapterChange,
 66→  mdxComponents,
 67→  offlineProps,
 68→}: PaginatedReaderProps) {
 69→  const containerRef = useRef<HTMLDivElement>(null);
 70→  const viewportRef = useRef<HTMLDivElement>(null);
 71→  const articleRef = useRef<HTMLElement>(null);
 72→  const [currentPage, setCurrentPage] = useState(0);
 73→  const [totalPages, setTotalPages] = useState(1);
 74→  const totalPagesRef = useRef(1);
 75→  totalPagesRef.current = totalPages;
 76→  const [pagesReady, setPagesReady] = useState(false);
 77→  const hasRestoredRef = useRef(false);
 78→  const saveTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
 79→  const skipTransitionRef = useRef(false);
 80→
 81→  // Detect ?page=last on initial render (backward chapter navigation)
 82→  const wantsLastPageRef = useRef(
 83→    typeof window !== "undefined" &&
 84→      new URLSearchParams(window.location.search).get("page") === "last"
 85→  );
 86→  // Hide content until page position is resolved (prevents flash at page 0
 87→  // before jumping to the saved page). Covers both ?page=last and normal restore.
 88→  const [awaitingRestore, setAwaitingRestore] = useState(
 89→    wantsLastPageRef.current || !!onRestoreProgress
 90→  );
 91→
 92→  // Multi-chapter state
 93→  const [loadedChapters, setLoadedChapters] = useState<LoadedChapter[]>([]);
 94→  const [chapterRanges, setChapterRanges] = useState<ChapterPageRange[]>([]);
 95→  const [activeChapterSlug, setActiveChapterSlug] = useState(
 96→    currentChapterSlug || ""
 97→  );
 98→  const preloadingRef = useRef<Set<string>>(new Set());
 99→
100→  // Whether we're in multi-chapter mode
101→  const isMultiChapter = !!(
102→    chapterMapData &&
103→    initialContent &&
104→    currentChapterSlug &&
105→    allChapters
106→  );
107→
108→  // Initialize loaded chapters
109→  useEffect(() => {
110→    if (isMultiChapter && initialContent && currentChapterSlug) {
111→      const chapterInfo = allChapters!.find(
112→        (ch) => ch.slug === currentChapterSlug
113→      );
114→      setLoadedChapters([
115→        {
116→          slug: currentChapterSlug,
117→          title: chapterInfo?.title || currentChapterSlug,
118→          Content: initialContent,
119→        },
120→      ]);
121→      setActiveChapterSlug(currentChapterSlug);
122→    }
123→  }, []); // Only on mount
124→
125→  // Clean up ?page=last from the URL on mount
126→  useEffect(() => {
127→    if (wantsLastPageRef.current) {
128→      const url = new URL(window.location.href);
129→      url.searchParams.delete("page");
130→      history.replaceState(null, "", url.pathname);
131→    }
132→  }, []);
133→
134→  // Settings & TOC panel state
135→  const [settingsOpen, setSettingsOpen] = useState(false);
136→  const [tocOpen, setTocOpen] = useState(false);
137→  const [activeTheme, setActiveTheme] = useState<string>(() => {
138→    if (typeof localStorage !== "undefined") {
139→      return localStorage.getItem("pressy-theme") || "light";
140→    }
141→    return "light";
142→  });
143→  const [fontScale, setFontScale] = useState<number>(() => {
144→    if (typeof localStorage !== "undefined") {
145→      const saved = localStorage.getItem("pressy-font-size");
146→      return saved ? parseFloat(saved) : 1.0;
147→    }
148→    return 1.0;
149→  });
150→
151→  const applyFontScale = useCallback((scale: number) => {
152→    if (scale === 1.0) {
153→      document.documentElement.style.removeProperty("--font-size-base");
154→    } else {
155→      document.documentElement.style.setProperty(
156→        "--font-size-base",
157→        `calc(clamp(1rem, 0.875rem + 0.5vw, 1.25rem) * ${scale})`
158→      );
159→    }
160→  }, []);
161→
162→  // Apply saved font scale on mount
163→  useEffect(() => {
164→    if (fontScale !== 1.0) {
165→      applyFontScale(fontScale);
166→    }
167→  }, []);
168→
169→  // Sync real viewport height to CSS custom property.
170→  // 100dvh is unreliable on Android PWAs where the system nav bar
171→  // overlaps the content. window.innerHeight always reflects the
172→  // actual usable area.
173→  useEffect(() => {
174→    const container = containerRef.current;
175→    if (!container) return;
176→
177→    const syncHeight = () => {
178→      container.style.setProperty("--app-height", `${window.innerHeight}px`);
179→    };
180→    syncHeight();
181→
182→    window.addEventListener("resize", syncHeight);
183→    window.visualViewport?.addEventListener("resize", syncHeight);
184→    return () => {
185→      window.removeEventListener("resize", syncHeight);
186→      window.visualViewport?.removeEventListener("resize", syncHeight);
187→    };
188→  }, []);
189→
190→  const handleThemeChange = useCallback((theme: string) => {
191→    setActiveTheme(theme);
192→    localStorage.setItem("pressy-theme", theme);
193→    const resolved =
194→      theme === "system"
195→        ? window.matchMedia("(prefers-color-scheme: dark)").matches
196→          ? "dark"
197→          : "light"
198→        : theme;
199→    document.documentElement.setAttribute("data-theme", resolved);
200→  }, []);
201→
202→  // Drag/swipe state
203→  const [isDragging, setIsDragging] = useState(false);
204→  const [dragOffset, setDragOffset] = useState(0);
205→  const [chapterHint, setChapterHint] = useState<"next" | "prev" | null>(null);
206→
207→  // Touch tracking refs (avoid re-renders during drag)
208→  const touchStartXRef = useRef(0);
209→  const touchStartYRef = useRef(0);
210→  const lastTouchXRef = useRef(0);
211→  const lastTouchTimeRef = useRef(0);
212→  const velocityRef = useRef(0);
213→  const isSwipingRef = useRef(false);
214→  const isDraggingRef = useRef(false);
215→
216→  // Build page-to-chapter map after recalculating pages
217→  const updateChapterRanges = useCallback(() => {
218→    if (!isMultiChapter) return;
219→    const article = articleRef.current;
220→    const viewport = viewportRef.current;
221→    if (!article || !viewport) return;
222→
223→    const viewportWidth = viewport.clientWidth;
224→    if (viewportWidth === 0) return;
225→
226→    const sections = article.querySelectorAll(".pressy-chapter-section");
227→    const ranges: ChapterPageRange[] = [];
228→
229→    sections.forEach((section) => {
230→      const slug = section.getAttribute("data-chapter-slug") || "";
231→      const sectionLeft = (section as HTMLElement).offsetLeft;
232→      const sectionWidth = (section as HTMLElement).scrollWidth;
233→      const startPage = Math.floor(sectionLeft / viewportWidth);
234→      const endPage = Math.max(
235→        startPage,
236→        Math.ceil((sectionLeft + sectionWidth) / viewportWidth) - 1
237→      );
238→      ranges.push({ slug, startPage, endPage });
239→    });
240→
241→    setChapterRanges(ranges);
242→  }, [isMultiChapter]);
243→
244→  // Calculate page count and set column-width to match viewport
245→  const recalculatePages = useCallback(() => {
246→    const article = articleRef.current;
247→    const viewport = viewportRef.current;
248→    if (!article || !viewport) return;
249→
250→    const viewportWidth = viewport.clientWidth;
251→    if (viewportWidth === 0) return;
252→
253→    // Set column-width to viewport width so each column = one page
254→    article.style.columnWidth = `${viewportWidth}px`;
255→
256→    // Force synchronous layout recalculation
257→    void article.scrollWidth;
258→
259→    const total = Math.max(1, Math.round(article.scrollWidth / viewportWidth));
260→    setTotalPages(total);
261→    setPagesReady(true);
262→
263→    // Clamp current page if now out of bounds (e.g. after resize)
264→    setCurrentPage((prev) => Math.min(prev, total - 1));
265→
266→    // Update chapter ranges for multi-chapter mode
267→    updateChapterRanges();
268→  }, [updateChapterRanges]);
269→
270→  // Font size change handler (defined after recalculatePages)
271→  const handleFontSizeChange = useCallback(
272→    (delta: number) => {
273→      setFontScale((prev) => {
274→        const next =
275→          Math.round(Math.max(0.8, Math.min(1.5, prev + delta)) * 10) / 10;
276→        localStorage.setItem("pressy-font-size", String(next));
277→        applyFontScale(next);
278→        setTimeout(() => recalculatePages(), 100);
279→        return next;
280→      });
281→    },
282→    [applyFontScale, recalculatePages]
283→  );
284→
285→  // Recalculate on mount and on resize via ResizeObserver
286→  useEffect(() => {
287→    const viewport = viewportRef.current;
288→    if (!viewport) return;
289→
290→    // Delay initial calculation to let fonts and content render
291→    const initialTimer = setTimeout(recalculatePages, 50);
292→
293→    const observer = new ResizeObserver(() => {
294→      recalculatePages();
295→    });
296→    observer.observe(viewport);
297→
298→    return () => {
299→      clearTimeout(initialTimer);
300→      observer.disconnect();
301→    };
302→  }, [recalculatePages]);
303→
304→  // Recalculate when loaded chapters change
305→  useEffect(() => {
306→    if (loadedChapters.length > 0) {
307→      // Delay to let new content render
308→      const timer = setTimeout(recalculatePages, 50);
309→      return () => clearTimeout(timer);
310→    }
311→  }, [loadedChapters.length, recalculatePages]);
312→
313→  // Recalculate when images finish loading
314→  useEffect(() => {
315→    const article = articleRef.current;
316→    if (!article) return;
317→
318→    const images = article.querySelectorAll("img");
319→    if (images.length === 0) return;
320→
321→    const onLoad = () => recalculatePages();
322→    images.forEach((img) => {
323→      if (!img.complete) {
324→        img.addEventListener("load", onLoad);
325→        img.addEventListener("error", onLoad);
326→      }
327→    });
328→
329→    return () => {
330→      images.forEach((img) => {
331→        img.removeEventListener("load", onLoad);
332→        img.removeEventListener("error", onLoad);
333→      });
334→    };
335→  }, [recalculatePages, loadedChapters.length]);
336→
337→  // Restore page position once pages are first computed.
338→  // Handles both ?page=last (backward chapter nav) and normal restore from
339→  // localStorage in a single effect — no racing between separate effects.
340→  // Uses pagesReady (not totalPages > 1) so single-page chapters work too.
341→  useEffect(() => {
342→    if (hasRestoredRef.current || !pagesReady) return;
343→
344→    // 1. ?page=last takes priority (backward chapter navigation)
345→    if (wantsLastPageRef.current) {
346→      wantsLastPageRef.current = false;
347→      skipTransitionRef.current = true;
348→      setCurrentPage(totalPages - 1);
349→      hasRestoredRef.current = true;
350→      setAwaitingRestore(false);
351→      return;
352→    }
353→
354→    // 2. Try to restore from saved progress
355→    if (!onRestoreProgress) {
356→      hasRestoredRef.current = true;
357→      setAwaitingRestore(false);
358→      return;
359→    }
360→
361→    onRestoreProgress().then((data) => {
362→      if (hasRestoredRef.current) {
363→        setAwaitingRestore(false);
364→        return;
365→      }
366→
367→      const currentTotalPages = totalPagesRef.current;
368→
369→      if (!data || data.page <= 0) {
370→        hasRestoredRef.current = true;
371→        setAwaitingRestore(false);
372→        return;
373→      }
374→
375→      let targetPage: number;
376→      if (
377→        data.totalPages <= 1 ||
378→        Math.abs(data.totalPages - currentTotalPages) <= 2
379→      ) {
380→        // Saved totalPages is degenerate (<=1) or very close to current —
381→        // use saved page directly. Clamping below handles out-of-bounds.
382→        targetPage = data.page;
383→      } else {
384→        // Significantly different layout — scale proportionally
385→        const fraction = data.page / (data.totalPages - 1);
386→        targetPage = Math.round(fraction * (currentTotalPages - 1));
387→      }
388→
389→      const clamped = Math.max(
390→        0,
391→        Math.min(targetPage, currentTotalPages - 1)
392→      );
393→      skipTransitionRef.current = true;
394→      setCurrentPage(clamped);
395→      hasRestoredRef.current = true;
396→      setAwaitingRestore(false);
397→    });
398→  }, [pagesReady, totalPages, onRestoreProgress]);
399→
400→  // Apply translateX — combines page position + drag offset

400→  // Apply translateX — combines page position + drag offset
401→  useEffect(() => {
402→    const article = articleRef.current;
403→    const viewport = viewportRef.current;
404→    if (!article || !viewport) return;
405→
406→    const baseOffset = currentPage * viewport.clientWidth;
407→    const totalOffset = baseOffset - dragOffset;
408→
409→    if (isDragging || skipTransitionRef.current) {
410→      // During drag or programmatic restore: no transition, immediate response
411→      article.style.transition = "none";
412→      skipTransitionRef.current = false;
413→    } else {
414→      // Snap animation: smooth ease-out
415→      article.style.transition =
416→        "transform 0.3s cubic-bezier(0.25, 0.46, 0.45, 0.94)";
417→    }
418→
419→    article.style.transform = `translateX(-${totalOffset}px)`;
420→  }, [currentPage, dragOffset, isDragging]);
421→
422→  // Manage focusability: elements on off-screen pages get tabindex="-1"
423→  // so tab navigation can't reach them and cause layout shifts.
424→  // Uses getBoundingClientRect which accounts for the CSS transform.
425→  useEffect(() => {
426→    const article = articleRef.current;
427→    const viewport = viewportRef.current;
428→    if (!article || !viewport) return;
429→
430→    const viewportRect = viewport.getBoundingClientRect();
431→
432→    const focusable = article.querySelectorAll<HTMLElement>(
433→      "a[href], button, input, select, textarea, [tabindex]"
434→    );
435→
436→    focusable.forEach((el) => {
437→      const elRect = el.getBoundingClientRect();
438→      const onCurrentPage =
439→        elRect.left >= viewportRect.left - 1 &&
440→        elRect.right <= viewportRect.right + 1;
441→
442→      if (onCurrentPage) {
443→        const original = el.getAttribute("data-original-tabindex");
444→        if (original !== null) {
445→          if (original === "") {
446→            el.removeAttribute("tabindex");
447→          } else {
448→            el.setAttribute("tabindex", original);
449→          }
450→          el.removeAttribute("data-original-tabindex");
451→        }
452→      } else {
453→        if (!el.hasAttribute("data-original-tabindex")) {
454→          el.setAttribute(
455→            "data-original-tabindex",
456→            el.getAttribute("tabindex") || ""
457→          );
458→        }
459→        el.setAttribute("tabindex", "-1");
460→      }
461→    });
462→  }, [currentPage, totalPages]);
463→
464→  // Preload next chapter when within 2 pages of chapter end
465→  useEffect(() => {
466→    if (!isMultiChapter || !chapterMapData || chapterRanges.length === 0)
467→      return;
468→
469→    const activeRange = chapterRanges.find((r) => r.slug === activeChapterSlug);
470→    if (!activeRange) return;
471→
472→    const pagesFromEnd = activeRange.endPage - currentPage;
473→    if (pagesFromEnd > 2) return;
474→
475→    // Find the next chapter to preload
476→    const { chapterOrder, chapterMap } = chapterMapData;
477→    const lastLoadedSlug = loadedChapters[loadedChapters.length - 1]?.slug;
478→    const lastLoadedIdx = chapterOrder.indexOf(lastLoadedSlug);
479→    if (lastLoadedIdx === -1 || lastLoadedIdx >= chapterOrder.length - 1)
480→      return;
481→
482→    const nextSlug = chapterOrder[lastLoadedIdx + 1];
483→    if (preloadingRef.current.has(nextSlug)) return;
484→    if (loadedChapters.some((ch) => ch.slug === nextSlug)) return;
485→
486→    preloadingRef.current.add(nextSlug);
487→
488→    const loader = chapterMap[nextSlug];
489→    if (!loader) return;
490→
491→    loader()
492→      .then((mod) => {
493→        const Content = mod.default;
494→        const chapterInfo = allChapters!.find((ch) => ch.slug === nextSlug);
495→        setLoadedChapters((prev) => {
496→          if (prev.some((ch) => ch.slug === nextSlug)) return prev;
497→          return [
498→            ...prev,
499→            {
500→              slug: nextSlug,
501→              title: chapterInfo?.title || nextSlug,
502→              Content,
503→            },
504→          ];
505→        });
506→      })
507→      .catch(() => {
508→        // Dynamic import failed — will fall back to full-page navigation
509→        preloadingRef.current.delete(nextSlug);
510→      });
511→  }, [
512→    currentPage,
513→    activeChapterSlug,
514→    chapterRanges,
515→    isMultiChapter,
516→    chapterMapData,
517→    loadedChapters,
518→    allChapters,
519→  ]);
520→
521→  // Detect chapter boundary crossings and update URL / active chapter
522→  useEffect(() => {
523→    if (!isMultiChapter || chapterRanges.length === 0 || !bookBasePath) return;
524→
525→    const currentRange = chapterRanges.find(
526→      (r) => currentPage >= r.startPage && currentPage <= r.endPage
527→    );
